/bin/sh -lc "cat > /workspace/work/audit_plan.json << 'PLANEOF'
{
  \"task_id\": \"L3-007\",
  \"task_type\": \"two_hop_retrieval\",
  \"complexity\": 2,
  \"question\": \"报销办法没有直接列审批金额时,请通过交叉引用找到单笔费用审批档位。\",
  \"scope\": {
    \"rule_clauses\": [
      {\"doc_id\": \"01_expense_reimbursement_2025.md\", \"clause\": \"第五条\", \"summary\": \"单笔费用报销审批权限不在本办法列示,统一按《XX证券授权管理办法》附件二执行\"},
      {\"doc_id\": \"03_authorization_management.md\", \"clause\": \"附件二\", \"summary\": \"费用报销审批权限表: AR-01至AR-05五档审批线\"}
    ],
    \"applies_to\": \"所有单笔费用报销记录,需交叉引用授权管理办法附件二确定审批档位\"
  },
  \"steps\": [
    {\"phase\": \"planning\", \"action\": \"记录 planning_completed checkpoint\", \"status\": \"pending\"},
    {\"phase\": \"investigation\", \"action\": \"交叉引用:通过报销办法第五条找到授权管理办法附件二,获取审批档位表\", \"status\": \"pending\"},
    {\"phase\": \"investigation\", \"action\": \"分析费用报销记录,将每笔金额映射到对应审批档位\", \"status\": \"pending\"},
    {\"phase\": \"investigation\", \"action\": \"检查是否存在审批角色缺失或错配的记录\", \"status\": \"pending\"},
    {\"phase\": \"review\", \"action\": \"evidence-coverage-check, false-positive-review\", \"status\": \"pending\"},
    {\"phase\": \"report\", \"action\": \"audit-report, result-validator\", \"status\": \"pending\"},
    {\"phase\": \"submit\", \"action\": \"validate_audit_result, submit_audit_result\", \"status\": \"pending\"}
  ],
  \"subagent_plan\": null
}
PLANEOF
echo \"audit_plan.json saved\""

